प्रकार्य validateParens(str) {
  कोष्ठक काउन्टर = ० दिनुहोस्;
  को लागी (i = 0; i <str.length; i++) {
    यदि (str[i] === '(') {
      कोष्ठक काउन्टर++;
    } अन्यथा यदि (str[i] === ')') {
      कोष्ठक काउन्टर--;
    }

    यदि (कोष्ठक काउन्टर <0) {
      गलत फिर्ता;
    }
  }
  फिर्ता कोष्ठक काउन्टर === 0;
}
